class Solution:
    def minimumRefill(self, plants, capacityA, capacityB):
        n = len(plants)

        def simulate_side(seq, capacity):
            refills = 0
            water = capacity
            for need in seq:
                if water < need:
                    refills += 1
                    water = capacity
                water -= need
            return refills, water

        half = n // 2
        a_refills, a_left = simulate_side(plants[:half], capacityA)
        b_refills, b_left = simulate_side(list(reversed(plants[half + (n % 2):])), capacityB)
        total = a_refills + b_refills
        if n % 2 == 1:
            mid = plants[half]
            use = a_left if a_left >= b_left else b_left
            if use < mid:
                total += 1
        return total

