var minimumRefill = function(plants, capacityA, capacityB) {
    let i = 0, j = plants.length - 1;
    let a = capacityA, b = capacityB;
    let refills = 0;
    while (i < j) {
        if (a < plants[i]) {
            refills++;
            a = capacityA;
        }
        a -= plants[i];
        if (b < plants[j]) {
            refills++;
            b = capacityB;
        }
        b -= plants[j];
        i++;
        j--;
    }
    if (i === j && Math.max(a, b) < plants[i]) refills++;
    return refills;
};
